#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_SIZE 5

// Structure for Linear Queue
typedef struct {
 int arr[MAX_SIZE];
 int front;
 int rear;
} LinearQueue;

// Structure for Circular Queue
typedef struct {
 int arr[MAX_SIZE];
 int front;
 int rear;
 int size;
} CircularQueue;

// =============================================
// LINEAR QUEUE OPERATIONS
// =============================================

void initLinearQueue(LinearQueue *q) {
 q->front = -1;
 q->rear = -1;
}

bool isEmptyLinear(LinearQueue *q) {
 return q->front == -1 || q->front > q->rear;
}

bool isFullLinear(LinearQueue *q) {
 return q->rear == MAX_SIZE - 1;
}

void enqueueLinear(LinearQueue *q, int value) {
 if (isFullLinear(q)) {
 printf("Queue Overflow! Cannot enqueue %d\n", value);
 return;
 }

 // First element being added
 if (q->front == -1) {
 q->front = 0;
 }

 q->rear++;
 q->arr[q->rear] = value;
 printf("%d enqueued to linear queue\n", value);
}

int dequeueLinear(LinearQueue *q) {
 if (isEmptyLinear(q)) {
 printf("Queue Underflow! Queue is empty\n");
 return -1;
 }

 int value = q->arr[q->front];
 q->front++;

 // Reset queue when empty
 if (q->front > q->rear) {
 q->front = -1;
 q->rear = -1;
 }

 printf("%d dequeued from linear queue\n", value);
 return value;
}

int peekLinear(LinearQueue *q) {
 if (isEmptyLinear(q)) {
 printf("Queue is empty\n");
 return -1;
 }
 return q->arr[q->front];
}

void displayLinear(LinearQueue *q) {
 if (isEmptyLinear(q)) {
 printf("Queue is empty\n");
 return;
 }

 printf("Linear Queue: ");
 for (int i = q->front; i <= q->rear; i++) {
 printf("%d ", q->arr[i]);
 }
 printf("\nFront=%d, Rear=%d\n", q->front, q->rear);
}

// =============================================
// CIRCULAR QUEUE OPERATIONS
// =============================================

void initCircularQueue(CircularQueue *q) {
 q->front = -1;
 q->rear = -1;
 q->size = 0;
}

bool isEmptyCircular(CircularQueue *q) {
 return q->front == -1;
}

bool isFullCircular(CircularQueue *q) {
 return (q->rear + 1) % MAX_SIZE == q->front;
}

void enqueueCircular(CircularQueue *q, int value) {
 if (isFullCircular(q)) {
 printf("Queue is Full! Cannot enqueue %d\n", value);
 return;
 }

 // First element
 if (q->front == -1) {
 q->front = 0;
 }

 q->rear = (q->rear + 1) % MAX_SIZE;
 q->arr[q->rear] = value;
 q->size++;
 printf("%d enqueued to circular queue\n", value);
}

int dequeueCircular(CircularQueue *q) {
 if (isEmptyCircular(q)) {
 printf("Queue is Empty!\n");
 return -1;
 }

 int value = q->arr[q->front];

 // Last element being removed
 if (q->front == q->rear) {
 q->front = -1;
 q->rear = -1;
 } else {
 q->front = (q->front + 1) % MAX_SIZE;
 }

 q->size--;
 printf("%d dequeued from circular queue\n", value);
 return value;
}

int peekCircular(CircularQueue *q) {
 if (isEmptyCircular(q)) {
 printf("Queue is empty\n");
 return -1;
 }
 return q->arr[q->front];
}

int sizeCircular(CircularQueue *q) {
 return q->size;
}

void displayCircular(CircularQueue *q) {
 if (isEmptyCircular(q)) {
 printf("Queue is empty\n");
 return;
 }

 printf("Circular Queue: ");
 int i = q->front;
 while (1) {
 printf("%d ", q->arr[i]);
 if (i == q->rear) break;
 i = (i + 1) % MAX_SIZE;
 }
 printf("\nFront=%d, Rear=%d, Size=%d\n", q->front, q->rear, q->size);
}

// =============================================
// MAIN FUNCTION - DEMONSTRATION
// =============================================

int main() {
 printf("====================================\n");
 printf("Linear Queue Operations\n");
 printf("====================================\n");

 LinearQueue lq;
 initLinearQueue(&lq);

 enqueueLinear(&lq, 10);
 enqueueLinear(&lq, 20);
 enqueueLinear(&lq, 30);
 displayLinear(&lq);

 dequeueLinear(&lq);
 displayLinear(&lq);

 printf("Peek: %d\n", peekLinear(&lq));

 printf("\n====================================\n");
 printf("Circular Queue Operations\n");
 printf("====================================\n");

 CircularQueue cq;
 initCircularQueue(&cq);

 // Fill the queue
 for (int i = 1; i <= 5; i++) {
 enqueueCircular(&cq, i * 10);
 }
 displayCircular(&cq);

 // Dequeue some elements
 dequeueCircular(&cq);
 dequeueCircular(&cq);

 // Enqueue more to show circular wrapping
 enqueueCircular(&cq, 60);
 enqueueCircular(&cq, 70);

 displayCircular(&cq);

 printf("\n====================================\n");
 printf("Demonstrating Linear Queue Problem\n");
 printf("====================================\n");

 // Show the linear queue problem
 LinearQueue lq2;
 initLinearQueue(&lq2);

 enqueueLinear(&lq2, 1);
 enqueueLinear(&lq2, 2);
 enqueueLinear(&lq2, 3);
 enqueueLinear(&lq2, 4);
 enqueueLinear(&lq2, 5); // Queue is now full

 dequeueLinear(&lq2); // Remove 1
 dequeueLinear(&lq2); // Remove 2

 // Cannot add more - false overflow!
 printf("Attempting to enqueue after some dequeues:\n");
 enqueueLinear(&lq2, 6); // This will show overflow!

 return 0;
}

/**
 * Queue Operations Implementation in Java
 * Demonstrates Array-based Queue and Linked List based Queue
