import java.util.NoSuchElementException;

// Generic Array Queue
class ArrayQueue<T> {
 private Object[] array;
 private int front;
 private int rear;
 private int capacity;
 private int size;

 public ArrayQueue(int capacity) {
 this.capacity = capacity;
 this.array = new Object[capacity];
 this.front = -1;
 this.rear = -1;
 this.size = 0;
 }

 public boolean isEmpty() {
 return front == -1;
 }

 public boolean isFull() {
 return (rear + 1) % capacity == front;
 }

 public int size() {
 return size;
 }

 public void enqueue(T item) {
 if (isFull()) {
 throw new IllegalStateException("Queue is Full! Overflow");
 }

 if (front == -1) {
 front = 0;
 }

 rear = (rear + 1) % capacity;
 array[rear] = item;
 size++;
 System.out.println(item + " enqueued to queue");
 }

 @SuppressWarnings("unchecked")
 public T dequeue() {
 if (isEmpty()) {
 throw new NoSuchElementException("Queue is Empty! Underflow");
 }

 T item = (T) array[front];

 if (front == rear) {
 // Queue becomes empty
 front = -1;
 rear = -1;
 } else {
 front = (front + 1) % capacity;
 }

 size--;
 System.out.println(item + " dequeued from queue");
 return item;
 }

 @SuppressWarnings("unchecked")
 public T peek() {
 if (isEmpty()) {
 throw new NoSuchElementException("Queue is Empty");
 }
 return (T) array[front];
 }

 public void display() {
 if (isEmpty()) {
 System.out.println("Queue is empty");
 return;
 }

 System.out.print("Queue: ");
 int i = front;
 while (true) {
 System.out.print(array[i] + " ");
 if (i == rear) break;
 i = (i + 1) % capacity;
 }
 System.out.println("\nFront=" + front + ", Rear=" + rear + ", Size=" + size);
 }
}

// Node for Linked List Queue
class QueueNode<T> {
 T data;
 QueueNode<T> next;

 public QueueNode(T data) {
 this.data = data;
 this.next = null;
 }
}

// Linked List based Queue
class LinkedQueue<T> {
 private QueueNode<T> front;
 private QueueNode<T> rear;
 private int size;

 public LinkedQueue() {
 this.front = null;
 this.rear = null;
 this.size = 0;
 }

 public boolean isEmpty() {
 return front == null;
 }

 public int size() {
 return size;
 }

 public void enqueue(T item) {
 QueueNode<T> newNode = new QueueNode<>(item);

 if (isEmpty()) {
 front = rear = newNode;
 } else {
 rear.next = newNode;
 rear = newNode;
 }

 size++;
 System.out.println(item + " enqueued to linked queue");
 }

 public T dequeue() {
 if (isEmpty()) {
 throw new NoSuchElementException("Queue is Empty! Underflow");
 }

 T item = front.data;
 front = front.next;

 if (front == null) {
 rear = null;
 }

 size--;
 System.out.println(item + " dequeued from linked queue");
 return item;
 }

 public T peek() {
 if (isEmpty()) {
 throw new NoSuchElementException("Queue is Empty");
 }
 return front.data;
 }

 public void display() {
 if (isEmpty()) {
 System.out.println("Linked Queue is empty");
 return;
 }

 System.out.print("Linked Queue: ");
 QueueNode<T> current = front;
 while (current != null) {
 System.out.print(current.data + " ");
 current = current.next;
 }
 System.out.println("\nSize=" + size);
 }
}

// Main Demonstration Class
public class QueueOperations {
 public static void main(String[] args) {
 System.out.println("====================================");
 System.out.println("Array-based Circular Queue");
 System.out.println("====================================");

 ArrayQueue<Integer> arrayQueue = new ArrayQueue<>(5);

 // Enqueue elements
 arrayQueue.enqueue(10);
 arrayQueue.enqueue(20);
 arrayQueue.enqueue(30);
 arrayQueue.display();

 // Dequeue element
 arrayQueue.dequeue();
 arrayQueue.display();

 // Peek
 System.out.println("Peek: " + arrayQueue.peek());

 // Show circular nature - add more than initial capacity
 System.out.println("\n--- Adding after wrapping around ---");
 arrayQueue.enqueue(40);
 arrayQueue.enqueue(50);
 arrayQueue.enqueue(60); // Should work due to circular nature
 arrayQueue.display();

 System.out.println("\n====================================");
 System.out.println("Linked List based Queue");
 System.out.println("====================================");

 LinkedQueue<String> linkedQueue = new LinkedQueue<>();

 linkedQueue.enqueue("Apple");
 linkedQueue.enqueue("Banana");
 linkedQueue.enqueue("Cherry");
 linkedQueue.display();

 linkedQueue.dequeue();
 linkedQueue.display();

 System.out.println("Peek: " + linkedQueue.peek());

 // Demonstrate queue operations with different types
 System.out.println("\n====================================");
 System.out.println("Generic Queue with Strings");
 System.out.println("====================================");

 ArrayQueue<String> stringQueue = new ArrayQueue<>(3);
 stringQueue.enqueue("university");
 stringQueue.enqueue("Study");
 stringQueue.enqueue("App");

 System.out.println("Size: " + stringQueue.size());

 try {
 stringQueue.enqueue("Extra"); // Will throw exception
 } catch (IllegalStateException e) {
 System.out.println("Caught: " + e.getMessage());
 }
 }
}
